% MATLAB State Machine Approach
t = linspace(0, 1, 1000);
x = sin(2*pi*10*t) .* exp(-3*t);

figure;
plot(t, x, 'b', 'LineWidth', 1.5);
title('Time Domain Signal');
xlabel('Time [s]');
ylabel('Amplitude [V]');
grid on;
legend('Damped Sine');

% MATLAB Subplot and semilogx
[b, a] = butter(4, 0.2, 'low');
[h, w] = freqz(b, a, 1024);
freq = w / pi;

figure;
subplot(2,1,1);
semilogx(freq, 20*log10(abs(h)), 'b');
title('Butterworth Filter Frequency Response');
ylabel('Magnitude [dB]');
grid on; ylim([-60, 5]);

subplot(2,1,2);
semilogx(freq, unwrap(angle(h)), 'g');
ylabel('Phase [radians]');
xlabel('Normalized Frequency (\times \pi rad/sample)');
grid on;

% MATLAB Constellation
N = 1000;
symbols = (randi([0 1], N, 1)*2-1) + 1j*(randi([0 1], N, 1)*2-1);
symbols = symbols / sqrt(2);
noise = (randn(N,1) + 1j*randn(N,1)) * 0.1;
rx_sig = symbols + noise;

scatterplot(rx_sig);
title('QPSK Constellation');
grid on;

% MATLAB Welch PSD
fs = 1000;
t = (0:1/fs:2-1/fs)';
x = sin(2*pi*50*t) + 0.5*sin(2*pi*120*t) + randn(length(t),1)*0.5;

figure;
pwelch(x, hann(256), 128, 256, fs);
% pwelch automatically plots in dB if no output arguments are provided

